	   udstdprcp_id
	 , evl_plan_id
	 , nm
	 , gender_cd
	 , instt_nm
	 , last_schul
	 , subjct
	 , enc_brthdy
	 , enc_mbtlnum
	 , bizrno
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values

	(
	   #{item.udstdprcpId}
	 , #{item.evlPlanId}
	 , #{item.nm}
	 , #{item.genderCd}
	 , #{item.insttNm}
	 , #{item.lastSchul}
	 , #{item.subjct}
	 , #{item.encBrthdy}
	 , #{item.encMbtlnum}
	 , #{item.bizrno}
	 , #{item.creatorId}
	 , #{item.createdDt}
	 , #{item.updaterId}
	 , #{item.updatedDt}
	)

